mapper.select:
SELECT
FROM coupons WHERE deleted_at IS NULL
AND name LIKE CONCAT('%', #{name}, '%')
AND type = #{type}
AND status = #{status}
ORDER BY created_at DESC

SELECT c.*
FROM coupons c
INNER JOIN user_coupons uc ON c.id = uc.coupon_id
WHERE uc.deleted_at IS NULL
  AND c.deleted_at IS NULL
  AND uc.user_id = #{userId}
  AND uc.status = 0
  AND c.valid_start_time <= #{now}
  AND c.valid_end_time >= #{now}
  AND c.min_amount <= #{orderAmount}
ORDER BY c.min_amount DESC, c.amount DESC, c.discount ASC

mapper.update:
UPDATE coupons
SET used_count = used_count + 1
WHERE id = #{id}
